# Problem: Implement WebSocket connection management and streaming response patterns.
#
# Approach:
# - WebSocketManager maintains dicts for connections (client_id -> Connection)
#   and rooms (room_name -> set of client_ids). Connection objects hold an outbox list.
# - StreamingResponse splits content into fixed-size chunks and yields StreamChunk objects.
# - SSEFormatter builds the standard SSE text format with data/event/id fields.
#
# Time complexity: O(n) for broadcast/disconnect where n = clients in room.
# Space complexity: O(c + r) where c = connections, r = room memberships.
#
# Key steps:
# 1. Connection stores client_id, rooms set, and outbox list (FIFO via pop(0))
# 2. WebSocketManager.connect creates/retrieves connection, joins room, notifies others
# 3. WebSocketManager.disconnect removes from all rooms, notifies remaining members
# 4. broadcast sends to all room members except optional exclude
# 5. StreamingResponse slices content into chunk_size pieces
# 6. SSEFormatter builds "data: ...\n" lines with optional event/id prefixes

import time
from typing import Iterator
from pydantic import BaseModel, Field


class Message(BaseModel):
    sender: str
    content: str
    room: str = 'general'
    timestamp: float = Field(default_factory=time.time)
    msg_type: str = 'text'  # 'text', 'system', 'error'


class Connection:

    def __init__(self, client_id: str):
        self.client_id = client_id
        self.rooms: set[str] = set()
        self.outbox: list[Message] = []

    def receive(self) -> Message | None:
        # Pop oldest message from outbox (FIFO order)
        if self.outbox:
            return self.outbox.pop(0)
        return None


class WebSocketManager:

    def __init__(self):
        self.connections: dict[str, Connection] = {}
        self.rooms: dict[str, set[str]] = {}

    def connect(self, client_id: str, room: str = 'general') -> Connection:
        # Create connection if new, otherwise retrieve existing
        if client_id not in self.connections:
            self.connections[client_id] = Connection(client_id)
        conn = self.connections[client_id]
        conn.rooms.add(room)

        # Initialize room if needed
        if room not in self.rooms:
            self.rooms[room] = set()

        # Notify OTHER clients already in the room before adding the new one
        join_msg = Message(
            sender="system",
            content=f"{client_id} joined {room}",
            room=room,
            msg_type="system"
        )
        for cid in self.rooms[room]:
            if cid != client_id:
                self.connections[cid].outbox.append(join_msg)

        # Now add client to the room
        self.rooms[room].add(client_id)
        return conn

    def disconnect(self, client_id: str) -> list[str]:
        if client_id not in self.connections:
            return []
        conn = self.connections[client_id]
        rooms_list = sorted(conn.rooms)  # rooms the client was in

        for room in rooms_list:
            # Remove client from room
            if room in self.rooms:
                self.rooms[room].discard(client_id)
                # Notify remaining clients
                leave_msg = Message(
                    sender="system",
                    content=f"{client_id} left {room}",
                    room=room,
                    msg_type="system"
                )
                for cid in self.rooms[room]:
                    self.connections[cid].outbox.append(leave_msg)
                # Clean up empty rooms
                if not self.rooms[room]:
                    del self.rooms[room]

        del self.connections[client_id]
        return rooms_list

    def send_to(self, client_id: str, message: Message) -> bool:
        if client_id not in self.connections:
            return False
        self.connections[client_id].outbox.append(message)
        return True

    def broadcast(self, room: str, message: Message, exclude: str | None = None) -> int:
        if room not in self.rooms:
            return 0
        count = 0
        for cid in self.rooms[room]:
            if cid != exclude:
                self.connections[cid].outbox.append(message)
                count += 1
        return count

    def get_room_members(self, room: str) -> list[str]:
        if room not in self.rooms:
            return []
        return sorted(self.rooms[room])

    def get_client_rooms(self, client_id: str) -> list[str]:
        if client_id not in self.connections:
            return []
        return sorted(self.connections[client_id].rooms)


class StreamChunk(BaseModel):
    index: int
    data: str
    is_last: bool = False


class StreamingResponse:

    def __init__(self, content: str, chunk_size: int = 10):
        self.content = content
        self.chunk_size = chunk_size
        # Pre-split content into string chunks
        self._chunks: list[str] = []
        for i in range(0, max(len(content), 1), chunk_size):
            self._chunks.append(content[i:i + chunk_size])
        # Handle empty content edge case
        if not content:
            self._chunks = ['']

    def __iter__(self) -> Iterator[StreamChunk]:
        total = len(self._chunks)
        for i, data in enumerate(self._chunks):
            yield StreamChunk(index=i, data=data, is_last=(i == total - 1))

    def get_chunks(self) -> list[StreamChunk]:
        return list(self)

    def get_total_chunks(self) -> int:
        return len(self._chunks)


class SSEFormatter:

    @staticmethod
    def format_event(data: str, event: str | None = None, id: str | None = None) -> str:
        result = ""
        if event is not None:
            result += f"event: {event}\n"
        if id is not None:
            result += f"id: {id}\n"
        result += f"data: {data}\n"
        result += "\n"  # Blank line to terminate the event
        return result

    @staticmethod
    def format_stream(chunks: list[StreamChunk]) -> str:
        # Format each chunk as an SSE event and concatenate
        return "".join(
            SSEFormatter.format_event(chunk.data)
            for chunk in chunks
        )
